// Filtra eventos de Evolution API (MESSAGES_UPSERT) y extrae el texto
const body = $json.body ?? $json;
const data = body.data;

// Ignorar si no hay datos o si el mensaje lo enviamos nosotros
if (!data || !data.key || data.key.fromMe) {
  return [];
}

// Solo mensajes de texto (conversation o extendedTextMessage)
const text = data.message?.conversation
  || data.message?.extendedTextMessage?.text
  || '';

if (!text.trim()) {
  return [];
}

// Ignorar grupos (los JID de grupo terminan en @g.us)
if (String(data.key.remoteJid).endsWith('@g.us')) {
  return [];
}

return [{
  json: {
    sessionId: data.key.remoteJid,
    number: String(data.key.remoteJid).split('@')[0],
    text: text.trim(),
    instance: body.instance,
    pushName: data.pushName || ''
  }
}];

// ============================================================
// EDITA AQUI TU PROMPT DE VENTAS
// ============================================================
const SYSTEM_PROMPT = `PEGA AQUÍ TU PROMPT

(Ejemplo mientras tanto:)
Eres el asistente de ventas de Productos Capilares PG por WhatsApp.
Vendemos el Combo Biotina para el crecimiento y fortalecimiento del cabello.
Responde en español, con tono cálido y cercano, mensajes cortos como se escribe en WhatsApp.
Tu objetivo es resolver dudas y cerrar la venta. Si el cliente quiere comprar, pídele nombre, dirección y método de pago.`;
// ============================================================

const input = $('Filtrar y extraer').first().json;

// Historial desde Postgres (viene en orden DESC, lo invertimos)
const rows = $input.all()
  .map(i => i.json)
  .filter(r => r && r.role && r.content);
const history = rows.reverse().map(r => ({ role: r.role, content: r.content }));

// Agregar el mensaje nuevo del cliente
history.push({ role: 'user', content: input.text });

return [{
  json: {
    ...input,
    systemPrompt: SYSTEM_PROMPT,
    messages: history
  }
}];

