// Extrae el texto de la respuesta de Claude
const resp = $json;
const ctx = $('Preparar mensajes (EDITA TU PROMPT AQUÍ)').first().json;

let reply = '';
if (resp.stop_reason === 'refusal') {
  reply = 'Disculpa, no puedo ayudarte con eso. ¿Tienes alguna consulta sobre nuestros productos?';
} else {
  reply = (resp.content || [])
    .filter(b => b.type === 'text')
    .map(b => b.text)
    .join('\n')
    .trim();
}

if (!reply) {
  reply = 'Disculpa, ¿podrías repetirme tu consulta?';
}

return [{ json: { ...ctx, reply } }];

// Genera dos filas para guardar en chat_history
const d = $json;
return [
  { json: { session_id: d.sessionId, role: 'user', content: d.text } },
  { json: { session_id: d.sessionId, role: 'assistant', content: d.reply } }
];
